import boto3
import json
import time
from typing import Dict, Any, Callable

class SQSWorker:
    def __init__(self, queue_url: str, region_name: str = 'us-east-1'):
        self.queue_url = queue_url
        self.sqs = boto3.client('sqs', region_name=region_name)
        self.message_handlers: Dict[str, Callable] = {}
        self.running = False
    
    def register_handler(self, message_type: str, handler: Callable):
        """Register a handler function for a specific message type"""
        self.message_handlers[message_type] = handler
    
    def process_message(self, message: Dict[str, Any]):
        """Process a single SQS message"""
        try:
            body = message.get('Body')
            if isinstance(body, str):
                body = json.loads(body)
            
            message_type = body.get('type')
            if not message_type:
                print(f"Warning: Message has no type field: {body}")
                return False
            
            if message_type in self.message_handlers:
                handler = self.message_handlers[message_type]
                handler(body)
                return True
            else:
                print(f"Warning: No handler registered for message type: {message_type}")
                return False
                
        except Exception as e:
            print(f"Error processing message: {e}")
            return False
    
    def poll_messages(self, max_messages: int = 10, wait_time: int = 20):
        """Poll messages from SQS queue"""
        while self.running:
            try:
                response = self.sqs.receive_message(
                    QueueUrl=self.queue_url,
                    MaxNumberOfMessages=max_messages,
                    WaitTimeSeconds=wait_time,
                    MessageAttributeNames=['All'],
                    AttributeNames=['All']
                )
                
                messages = response.get('Messages', [])
                if messages:
                    for message in messages:
                        self.process_message(message)
                        
                        # Delete message after processing
                        self.sqs.delete_message(
                            QueueUrl=self.queue_url,
                            ReceiptHandle=message['ReceiptHandle']
                        )
                
                time.sleep(1)
                
            except Exception as e:
                print(f"Error polling messages: {e}")
                time.sleep(5)
    
    def start(self):
        """Start the worker"""
        self.running = True
        print("Starting SQS worker...")
        self.poll_messages()
    
    def stop(self):
        """Stop the worker"""
        self.running = False
        print("SQS worker stopped")

